1	type Grid = number[][];
2	
3	const countNeighbors = (grid: Grid, row: number, col: number): number => {
4	  let count = 0;
5	  for (let r = row - 1; r <= row + 1; r++) {
6	    for (let c = col - 1; c <= col + 1; c++) {
7	      if (r === row && c === col) continue;
8	      if (r >= 0 && r < grid.length && c >= 0 && c < grid[r].length) {
9	        count += grid[r][c];
10	      }
11	    }
12	  }
13	  return count;
14	};
15	
16	export function nextGeneration(grid: Grid): Grid {
17	  if (grid.length === 0) return [];
18	
19	  const nextGrid: Grid = grid.map((row, r) =>
20	    row.map((cell, c) => {
21	      const neighbors = countNeighbors(grid, r, c);
22	      const isAlive = cell === 1;
23	      const survives = isAlive && (neighbors === 2 || neighbors === 3);
24	      const isReborn = !isAlive && neighbors === 3;
25	      return survives || isReborn ? 1 : 0;
26	    })
27	  );
28	
29	  const hasLiveCells = nextGrid.some(row => row.some(cell => cell === 1));
30	  if (!hasLiveCells) return [];
31	
32	  return nextGrid;
33	}
